loan_no = #{loanNo}, customer_no = #{customerNo}, amount = #{amount}, term_months = #{termMonths}, interest_rate = #{interestRate}, loan_date = #{loanDate}, due_date = #{dueDate}, repay_method = #{repayMethod}, maturity_interest = #{maturityInterest}, maturity_total = #{maturityTotal}, repay_date = #{repayDate}, status = #{status}, updated_at = NOW()
WHERE id = #{id}

